def assess(record: dict) -> str:
    required = {"case_id", 'schema', 'row', 'catalog_ok'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if record["catalog_ok"] is True else "REJECT_UNKNOWN_FEATURE"

valid = {"case_id": "CASO-LIM-032-1A", **{'schema': {'numeric': ['amount_7d'], 'categorical': ['canal']}, 'row': {'amount_7d': 1.0, 'canal': 'app'}, 'catalog_ok': True}}
invalid = {"case_id": "CASO-LIM-032-1A", **{'schema': {'numeric': ['amount_7d']}, 'row': {'unknown_feat': 1}, 'catalog_ok': False}}
incomplete = {**valid}
incomplete.pop("schema")
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

def decide(record: dict) -> str:
    required = {"case_id", "schema", "row", "catalog_ok"}
    missing = sorted(required - record.keys())
    if missing:
        return "REQUEST_CATALOG"
    return "CONTINUE" if record.get("catalog_ok") is True else "REJECT_UNKNOWN_FEATURE"

valid = {"case_id": "CASO-LIM-032-1A", "schema": {"numeric": ["amount_7d"], "categorical": ["canal"]}, "row": {"amount_7d": 1.0, "canal": "app"}, "catalog_ok": True}
invalid = {"case_id": "CASO-LIM-032-1A", "schema": {"numeric": ["amount_7d"]}, "row": {"unknown_feat": 1}, "catalog_ok": False}
uncertain = {k: v for k, v in valid.items() if k != "schema"}
print(decide(valid), decide(invalid), decide(uncertain))

